import Dexie, { Table } from 'dexie';

export interface User {
  id?: number;
  shopName: string;
  ownerName: string;
  phone: string;
  password: string;
  language: string;
  createdAt: Date;
}

export interface Session {
  id: number;
  userId: number;
  lastActive: Date;
}

export interface Customer {
  id?: number;
  userId: number; // Scoped to user
  name: string;
  phone: string;
  photo?: string;
  totalDue: number;
  lastTransactionDate: Date;
  status: 'active' | 'overdue';
}

export interface Transaction {
  id?: number;
  userId: number; // Scoped to user
  customerId: number;
  amount: number;
  type: 'credit' | 'payment';
  description?: string;
  timestamp: Date;
}

export interface AiLog {
  id?: number;
  userId: number; // Scoped to user
  command: string;
  response: string;
  intent: string;
  timestamp: Date;
  type?: 'message' | 'form_new' | 'customer_card';
  data?: any;
}

export class KiranaDB extends Dexie {
  users!: Table<User>;
  sessions!: Table<Session>;
  customers!: Table<Customer>;
  transactions!: Table<Transaction>;
  ai_logs!: Table<AiLog>;

  constructor() {
    super('KiranaOS_DB_v2');
    this.version(1).stores({
      users: '++id, phone',
      sessions: 'id, userId',
      customers: '++id, userId, name',
      transactions: '++id, userId, customerId, timestamp',
      ai_logs: '++id, userId, timestamp'
    });
  }
}

export const db = new KiranaDB();
