"use client";

import { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useRouter } from "next/navigation";
import { useStore } from "@/lib/store/useStore";
import styles from "./Register.module.css";
import { Mic, Send, Radio, ArrowRight, Store, User, Phone, Lock, Languages } from "lucide-react";

const STEPS = [
  { key: 'shopName', question: "Hello! Welcome to Kirana OS. Let's set up your shop. What is your Shop Name?", icon: <Store /> },
  { key: 'ownerName', question: "Great name! And what is your name (Owner Name)?", icon: <User /> },
  { key: 'phone', question: "Nice to meet you. Please enter your Phone Number.", icon: <Phone /> },
  { key: 'password', question: "Security is important. Set a 4-digit PIN or Password.", icon: <Lock />, type: 'password' },
  { key: 'language', question: "Last step: Which language do you prefer?", icon: <Languages />, options: ['English', 'Hindi', 'Gujarati', 'Marathi'] }
];

export default function RegisterPage() {
  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState<any>({});
  const [input, setInput] = useState("");
  const [messages, setMessages] = useState<any[]>([]);
  const [isListening, setIsListening] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const router = useRouter();
  const { register, checkSession, isAuthenticated } = useStore();

  useEffect(() => {
    checkSession();
  }, [checkSession]);

  useEffect(() => {
    if (isAuthenticated) router.push('/');
  }, [isAuthenticated, router]);

  useEffect(() => {
    // Initial Greeting
    setMessages([{ type: 'ai', text: STEPS[0].question }]);
  }, []);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleNext = async (val?: string) => {
    const value = val || input.trim();
    if (!value && !STEPS[currentStep].options) return;

    const key = STEPS[currentStep].key;
    const newFormData = { ...formData, [key]: value };
    setFormData(newFormData);
    setMessages(prev => [...prev, { type: 'user', text: value }]);
    setInput("");

    if (currentStep < STEPS.length - 1) {
      setTimeout(() => {
        setMessages(prev => [...prev, { type: 'ai', text: STEPS[currentStep + 1].question }]);
        setCurrentStep(prev => prev + 1);
      }, 600);
    } else {
      // Complete Registration
      setTimeout(async () => {
        setMessages(prev => [...prev, { type: 'ai', text: "Perfect! Saving your shop details... Please wait." }]);
        await register(newFormData);
        setTimeout(() => router.push('/'), 1500);
      }, 600);
    }
  };

  return (
    <div className={styles.container}>
      <div className={styles.onboardingBox}>
        <header className={styles.header}>
          <div className={styles.logo}>
            <div className={styles.dot} />
            <span>KIRANA OS ONBOARDING</span>
          </div>
        </header>

        <div className={styles.chatArea} ref={scrollRef}>
          <AnimatePresence>
            {messages.map((msg, i) => (
              <motion.div 
                key={i}
                initial={{ opacity: 0, y: 10, scale: 0.95 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                className={msg.type === 'ai' ? styles.aiMsg : styles.userMsg}
              >
                {msg.type === 'ai' && <div className={styles.avatar}>AI</div>}
                <div className={styles.bubble}>{msg.text}</div>
              </motion.div>
            ))}
          </AnimatePresence>
        </div>

        <div className={styles.inputArea}>
          {STEPS[currentStep].options ? (
            <div className={styles.options}>
              {STEPS[currentStep].options.map(opt => (
                <button key={opt} onClick={() => handleNext(opt)} className={styles.optBtn}>
                  {opt}
                </button>
              ))}
            </div>
          ) : (
            <div className={styles.inputWrapper}>
              <div className={styles.stepIcon}>{STEPS[currentStep].icon}</div>
              <input 
                type={STEPS[currentStep].type || 'text'}
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleNext()}
                placeholder="Type your answer..."
                autoFocus
              />
              <button className={styles.sendBtn} onClick={() => handleNext()}>
                <Send size={20} />
              </button>
            </div>
          )}
        </div>
      </div>

      <div className={styles.bgOrb} />
    </div>
  );
}
