import { create } from 'zustand';
import { db, type User, type Customer, type Transaction, type AiLog } from '../db/dexie';

interface KiranaState {
  // Auth State
  currentUser: User | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  
  // Business Data
  customers: Customer[];
  transactions: Transaction[];
  aiLogs: AiLog[];
  
  // UI State
  orbState: 'idle' | 'listening' | 'processing' | 'success' | 'error';
  setOrbState: (state: 'idle' | 'listening' | 'processing' | 'success' | 'error') => void;

  // Auth Actions
  login: (phone: string, password: string) => Promise<boolean>;
  register: (user: Omit<User, 'id' | 'createdAt'>) => Promise<number>;
  logout: () => Promise<void>;
  checkSession: () => Promise<void>;

  // Data Actions
  fetchData: () => Promise<void>;
  searchCustomer: (name: string) => Customer | undefined;
  addCustomer: (customer: Omit<Customer, 'id' | 'userId'>) => Promise<number>;
  updateCustomer: (id: number, changes: Partial<Customer>) => Promise<void>;
  deleteCustomer: (id: number) => Promise<void>;
  addTransaction: (transaction: Omit<Transaction, 'id' | 'userId'>) => Promise<number>;
  addAiLog: (log: Omit<AiLog, 'id' | 'userId'>) => Promise<number>;
  clearAll: () => Promise<void>;
}

export const useStore = create<KiranaState>((set, get) => ({
  currentUser: null,
  isAuthenticated: false,
  isLoading: true,
  customers: [],
  transactions: [],
  aiLogs: [],
  orbState: 'idle',

  setOrbState: (state) => set({ orbState: state }),

  checkSession: async () => {
    const session = await db.sessions.get(1);
    if (session) {
      const user = await db.users.get(session.userId);
      if (user) {
        set({ currentUser: user, isAuthenticated: true });
        await get().fetchData();
      }
    }
    set({ isLoading: false });
  },

  register: async (userData) => {
    const user = {
      ...userData,
      createdAt: new Date()
    } as User;
    const id = await db.users.add(user);
    user.id = id as number;
    await db.sessions.put({ id: 1, userId: user.id, lastActive: new Date() });
    set({ currentUser: user, isAuthenticated: true });
    await get().fetchData();
    return id as number;
  },

  login: async (phone, password) => {
    const user = await db.users.where('phone').equals(phone).first();
    if (user && user.password === password) {
      await db.sessions.put({ id: 1, userId: user.id!, lastActive: new Date() });
      set({ currentUser: user, isAuthenticated: true });
      await get().fetchData();
      return true;
    }
    return false;
  },

  logout: async () => {
    await db.sessions.clear();
    set({ currentUser: null, isAuthenticated: false, customers: [], transactions: [], aiLogs: [] });
  },

  fetchData: async () => {
    const user = get().currentUser;
    if (!user) return;

    const [customers, transactions, aiLogs] = await Promise.all([
      db.customers.where('userId').equals(user.id!).toArray(),
      db.transactions.where('userId').equals(user.id!).sortBy('timestamp'),
      db.ai_logs.where('userId').equals(user.id!).sortBy('timestamp'),
    ]);

    // aiLogs should be chronological (Oldest first for the array, we display bottom-up)
    set({ 
      customers, 
      transactions: transactions.reverse(), 
      aiLogs, // Chronological order
      isLoading: false 
    });
  },

  searchCustomer: (name) => {
    if (!name || name.length < 2) return undefined;
    return get().customers.find(c => 
      c.name.toLowerCase() === name.toLowerCase() || 
      c.name.toLowerCase().startsWith(name.toLowerCase())
    );
  },

  addCustomer: async (customer) => {
    const user = get().currentUser;
    if (!user) throw new Error("No user logged in");
    
    const id = await db.customers.add({
      ...customer,
      userId: user.id!
    } as Customer);
    await get().fetchData();
    return id as number;
  },

  updateCustomer: async (id, changes) => {
    await db.customers.update(id, changes);
    await get().fetchData();
  },

  deleteCustomer: async (id) => {
    await db.customers.delete(id);
    await db.transactions.where('customerId').equals(id).delete();
    await get().fetchData();
  },

  addTransaction: async (transaction) => {
    const user = get().currentUser;
    if (!user) throw new Error("No user logged in");

    const id = await db.transactions.add({
      ...transaction,
      userId: user.id!
    } as Transaction);
    
    const customer = await db.customers.get(transaction.customerId);
    if (customer) {
      const newTotal = transaction.type === 'credit' 
        ? customer.totalDue + transaction.amount 
        : customer.totalDue - transaction.amount;
      
      await db.customers.update(transaction.customerId, { 
        totalDue: newTotal,
        lastTransactionDate: new Date()
      });
    }

    await get().fetchData();
    return id as number;
  },

  addAiLog: async (log) => {
    const user = get().currentUser;
    if (!user) throw new Error("No user logged in");

    const id = await db.ai_logs.add({
      ...log,
      userId: user.id!
    } as AiLog);
    await get().fetchData();
    return id as number;
  },

  clearAll: async () => {
    const user = get().currentUser;
    if (!user) throw new Error("No user logged in");

    await db.customers.where('userId').equals(user.id!).delete();
    await db.transactions.where('userId').equals(user.id!).delete();
    await db.ai_logs.where('userId').equals(user.id!).delete();
    await get().fetchData();
  },
}));
